using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The MCP SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods. Constructor parameters are resolved from DI.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    // The SDK instantiates this class per-call via DI.
    // HttpClient is injected by IHttpClientFactory (registered in Program.cs).
    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await _http.GetFromJsonAsync<WeatherResponse>(url);
        if (response?.Current is null)
            return "No weather data available.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool, Description("Look up geographic coordinates for a place name.")]
    public async Task<string> GeocodePlaceName(
        [Description("City or place name to look up")] string name)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(name)}&count=1";
        var response = await _http.GetFromJsonAsync<GeoResponse>(url);

        if (response?.Results is not { Count: > 0 })
            return $"No results found for '{name}'.";

        var r = response.Results[0];
        return $"{r.Name} ({r.Country}): lat={r.Latitude}, lon={r.Longitude}";
    }
}

// DTOs for Open-Meteo responses
public sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; set; }
}

public sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

public sealed class GeoResponse
{
    [JsonPropertyName("results")]
    public List<GeoResult>? Results { get; set; }
}

public sealed class GeoResult
{
    [JsonPropertyName("name")]
    public string Name { get; set; } = "";

    [JsonPropertyName("country")]
    public string Country { get; set; } = "";

    [JsonPropertyName("latitude")]
    public double Latitude { get; set; }

    [JsonPropertyName("longitude")]
    public double Longitude { get; set; }
}

